+      async deleteSelectedMessages() {
+        if (this.selectedMessages.length === 0) return;
+
+        const count = this.selectedMessages.length;
+        const confirmMsg = `Permanently delete ${count} selected message${count !== 1 ? 's' : ''}? This removes them from the database and Git archive and cannot be undone.`;
+        if (!confirm(confirmMsg)) return;
+
+        try {
+          const projectSlug = {{ project.slug | tojson }};
+          const agentName = {{ agent | tojson }};
+
+          const response = await fetch(`/mail/${projectSlug}/inbox/${agentName}/delete-messages`, {
+            method: 'POST',
+            headers: {
+              'Content-Type': 'application/json',
+            },
+            body: JSON.stringify({
+              message_ids: this.selectedMessages
+            })
+          });
+
+          if (!response.ok) {
+            const error = await response.json().catch(() => ({}));
+            throw new Error(error.detail || error.error || `Server error: ${response.status}`);
+          }
+
+          const result = await response.json();
+          const deletedCount = result.deleted_count || 0;
+
+          if (typeof window.showToast === 'function') {
+            window.showToast(
+              `Permanently deleted ${deletedCount} message${deletedCount !== 1 ? 's' : ''}`,
+              'success'
+            );
+          } else {
+            alert(`Permanently deleted ${deletedCount} message${deletedCount !== 1 ? 's' : ''}`);
+          }
+
+          this.clearSelection();
+
+          // Reload to show updated state
+          setTimeout(() => {
+            window.location.reload();
+          }, 1000);
+
+        } catch (error) {
+          console.error('Failed to delete messages:', error);
+
+          if (typeof window.showToast === 'function') {
+            window.showToast(
+              `Failed to delete messages: ${error.message}`,
+              'error'
+            );
+          } else {
+            alert(`Failed to delete messages: ${error.message}`);
+          }
+        }
+      },
